static const size_t song_len = sizeof(song) / sizeof(song[0]);

// Plays the song. Assumes you already have:
//   void play_note(uint32_t freq, uint32_t duration_ms);
//   void delay_ms(uint32_t ms);
static void play_song(void) {
    for (size_t i = 0; i < song_len; i++) {
        if (song[i].freq == 0) {
            delay_ms(song[i].duration_ms);
        } else {
            play_note(song[i].freq, song[i].duration_ms);
        }
    }
}
